def _cargar_equity_dia(fallback):
    import json
    if Path(EQUITY_DIA_FILE).exists():
        data = json.loads(Path(EQUITY_DIA_FILE).read_text())
        if data.get('fecha') == str(datetime.now(UTC).date()):
            return data['equity_dia']
    return fallback

def _guardar_equity_dia(equity_dia):
    import json
    Path(EQUITY_DIA_FILE).write_text(json.dumps({
        'fecha': str(datetime.now(UTC).date()),
        'equity_dia': equity_dia
    }))

